	["combat_math"] = [[local CombatMath = {}

CombatMath.TITLE_BONUSES = {
    ["executioner"] = 25000,
    ["destroyer"] = 50000,
    ["supreme reaper"] = 100000,
    ["notorious gladiator"] = 250000,
    ["legend"] = 500000,
    ["god"] = 1000000,
}

local DAMAGE_NAMES = { "Damage", "damage", "DMG", "Dmg", "ATK", "Atk", "Attack" }

local function finitePositive(value)
    value = tonumber(value)
    return value and value > 0 and value < math.huge and value or nil
end

local function readValue(parent, names)
    if not parent then return nil end
    for _, name in ipairs(names) do
        local item = parent:FindFirstChild(name)
        local value = item and finitePositive(item.Value)
        if value then return value end
    end
    return nil
end

function CombatMath.getLevel(player)
    return readValue(player and player:FindFirstChild("leaderstats"), { "Level", "level" })
end

function CombatMath.estimateDamageFromLevel(level)
    level = finitePositive(level)
    return level and (level * 2 + 10) or nil
end

function CombatMath.getDamage(player)
    local live = readValue(player and player:FindFirstChild("leaderstats"), DAMAGE_NAMES)
    return live or CombatMath.estimateDamageFromLevel(CombatMath.getLevel(player))
end

function CombatMath.normalizeTitle(text)
    if type(text) ~= "string" then return nil end
    local normalized = text:lower():gsub("[%c%p]", " "):gsub("%s+", " "):match("^%s*(.-)%s*$")
    for title in pairs(CombatMath.TITLE_BONUSES) do
        if normalized:find(title, 1, true) then return title end
    end
    return nil
end

function CombatMath.findTitle(player)
    local character = player and player.Character
    local head = character and character:FindFirstChild("Head")
    if not head then return nil end
    for _, descendant in ipairs(head:GetDescendants()) do
        local generatedOverlay = descendant:FindFirstAncestor("AnimalSimV2Combat")
        if not generatedOverlay and (descendant:IsA("TextLabel") or descendant:IsA("TextBox")) then
            local title = CombatMath.normalizeTitle(descendant.Text)
            if title then return title end
        end
    end
    return nil
end

function CombatMath.getTitleBonus(player, explicitTitle)
    local title = CombatMath.normalizeTitle(explicitTitle) or CombatMath.findTitle(player)
    return title and CombatMath.TITLE_BONUSES[title] or 0, title
end

function CombatMath.getHealth(player, options)
    options = type(options) == "table" and options or {}
    local humanoid = player and player.Character and player.Character:FindFirstChildOfClass("Humanoid")
    if humanoid then
        local current = tonumber(humanoid.Health)
        current = current and current >= 0 and current < math.huge and current or nil
        local maximum = finitePositive(humanoid.MaxHealth)
        if current ~= nil or maximum then return current or maximum, math.max(current or 0, maximum or 0), "live" end
    end
    local damage = CombatMath.getDamage(player)
    if not damage then return nil, nil, "unknown" end
    local bonus = CombatMath.getTitleBonus(player, options.title)
    local maximum = damage * 10 + bonus
    return maximum, maximum, "estimated"
end

function CombatMath.hitCount(health, damage)
    health, damage = finitePositive(health), finitePositive(damage)
    if not health or not damage then return nil end
    return math.max(1, math.ceil(health / damage))
end

function CombatMath.getMatchup(localPlayer, enemyPlayer, options)
    local _, ourHealth, ourHealthSource = CombatMath.getHealth(localPlayer, options and options.localHealth)
    local _, enemyHealth, enemyHealthSource = CombatMath.getHealth(enemyPlayer, options and options.enemyHealth)
    local ourDamage, enemyDamage = CombatMath.getDamage(localPlayer), CombatMath.getDamage(enemyPlayer)
    local ourTitleBonus, ourTitle = CombatMath.getTitleBonus(localPlayer)
    local enemyTitleBonus, enemyTitle = CombatMath.getTitleBonus(enemyPlayer)
    local ourHits = CombatMath.hitCount(enemyHealth, ourDamage)
    local enemyHits = CombatMath.hitCount(ourHealth, enemyDamage)
    local ratio = ourHits and enemyHits and (enemyHits / ourHits) or nil
    return {
        ourDamage = ourDamage, enemyDamage = enemyDamage,
        ourHealth = ourHealth, enemyHealth = enemyHealth,
        ourTitle = ourTitle, enemyTitle = enemyTitle,
        ourTitleBonus = ourTitleBonus, enemyTitleBonus = enemyTitleBonus,
        ourHitsToKill = ourHits, enemyHitsToKill = enemyHits,
        ratio = ratio, ourHealthSource = ourHealthSource, enemyHealthSource = enemyHealthSource,
    }
end

function CombatMath.passesTitleSafety(matchup)
    return matchup ~= nil and not (matchup.ourTitle == nil and matchup.enemyTitle ~= nil)
end

function CombatMath.passesRatio(matchup, threshold)
    threshold = finitePositive(threshold) or 1.5
    return CombatMath.passesTitleSafety(matchup)
        and matchup.ratio ~= nil
        and matchup.ratio >= threshold
        or false
end

return CombatMath
