FoodController.__index = FoodController

local function isFoodTool(instance)
    if not (instance and instance:IsA("Tool")) then
        return false
    end
    if string.lower(instance.Name) == "food" then
        return true
    end
    return instance:GetAttribute("IsFood") == true or instance:GetAttribute("Food") == true
end

function FoodController.new(player, config)
    return setmetatable({
        player = player,
        cooldown = config.fallbackFoodCooldown or 1,
        enabled = false,
        generation = 0,
        lastUsed = setmetatable({}, {__mode = "k"}),
        nextIndex = 1,
    }, FoodController)
end

function FoodController:_collect()
    local tools = {}
    local function scan(container)
        if not container then
            return
        end
        for _, child in ipairs(container:GetChildren()) do
            if isFoodTool(child) then
                table.insert(tools, child)
            end
        end
    end
    scan(self.player.Character)
    scan(self.player:FindFirstChildOfClass("Backpack") or self.player:FindFirstChild("Backpack"))
    table.sort(tools, function(a, b)
        return a.Name < b.Name
    end)
    return tools
end

function FoodController:_ready(tool, now)
    if tool.Enabled == false then
        return false
    end
    return now - (self.lastUsed[tool] or -math.huge) >= self.cooldown
end

function FoodController:_activate(tool, now)
    local character = self.player.Character
    local humanoid = character and character:FindFirstChildOfClass("Humanoid")
    if not (humanoid and tool and tool.Parent) then
        return false
    end
    if tool.Parent ~= character then
        humanoid:EquipTool(tool)
        task.wait(0.05)
    end
    if tool.Parent ~= character or tool.Enabled == false then
        return false
    end
    local ok = pcall(function()
        tool:Activate()
    end)
    if ok then
        self.lastUsed[tool] = now
    end
    return ok
end

function FoodController:setEnabled(enabled)
    enabled = enabled == true
    if self.enabled == enabled then
        return
    end
    self.enabled = enabled
    self.generation = self.generation + 1
    if not enabled then
        return
    end
    local token = self.generation
    task.spawn(function()
        while self.enabled and self.generation == token do
            local tools = self:_collect()
            if #tools == 0 then
                task.wait(0.25)
            else
                if self.nextIndex > #tools then
                    self.nextIndex = 1
                end
                local activated = false
                for offset = 0, #tools - 1 do
                    local index = ((self.nextIndex + offset - 1) % #tools) + 1
                    local tool = tools[index]
                    if self:_ready(tool, os.clock()) then
                        activated = self:_activate(tool, os.clock())
                        self.nextIndex = (index % #tools) + 1
                        if activated then
                            break
                        end
                    end
                end
                task.wait(activated and 0.05 or 0.1)
            end
        end
    end)
end

function FoodController:destroy()
    self:setEnabled(false)
    self.lastUsed = setmetatable({}, {__mode = "k"})
end

return FoodController
