local function resolveRequest()
	return (syn and syn.request) or http_request or request
end

function IntentClient.new(options)
	options = options or {}
	return setmetatable({
		url = options.url or "http://127.0.0.1:3636/intent",
		releaseUrl = options.releaseUrl or "http://127.0.0.1:3636/simulator/release",
		heldKeys = {},
		heldButtons = {},
		destroyed = false,
	}, IntentClient)
end

function IntentClient:_post(url, payload)
	if self.destroyed then return false, "destroyed" end
	local body = HttpService:JSONEncode(payload or {})
	local requester = resolveRequest()
	local ok, response
	if requester then
		ok, response = pcall(requester, {
			Url = url,
			Method = "POST",
			Headers = { ["Content-Type"] = "application/json" },
			Body = body,
		})
	else
		ok, response = pcall(HttpService.PostAsync, HttpService, url, body, Enum.HttpContentType.ApplicationJson, false)
	end
	if not ok then return false, tostring(response) end
	if type(response) == "table" and response.StatusCode and response.StatusCode >= 400 then
		return false, "HTTP " .. tostring(response.StatusCode)
	end
	return true, response
end

function IntentClient:setKey(key, down)
	key = string.upper(tostring(key))
	if self.heldKeys[key] == down then return true end
	local ok, err = self:_post(self.url, { event = down and "keydown" or "keyup", key = key })
	if ok then self.heldKeys[key] = down or nil end
	return ok, err
end

function IntentClient:tapKey(key)
	return self:_post(self.url, { event = "press", key = string.upper(tostring(key)) })
end

function IntentClient:setMouseButton(button, down)
	button = string.lower(button or "left")
	if self.heldButtons[button] == down then return true end
	local ok, err = self:_post(self.url, { event = down and "keydown" or "keyup", button = button })
	if ok then self.heldButtons[button] = down or nil end
	return ok, err
end

function IntentClient:click(button)
	return self:_post(self.url, { event = "press", button = string.lower(button or "left") })
end

function IntentClient:moveMouse(dx, dy)
	return self:_post(self.url, { mouseDx = dx or 0, mouseDy = dy or 0 })
end

function IntentClient:releaseAll()
	local wasDestroyed = self.destroyed
	self.destroyed = false
	local ok, err = self:_post(self.releaseUrl, {})
	self.heldKeys = {}
	self.heldButtons = {}
	self.destroyed = wasDestroyed
	return ok, err
end

function IntentClient:destroy()
	if self.destroyed then return end
	self:releaseAll()
	self.destroyed = true
end

return IntentClient
