	["player_discovery"] = [[local PlayerDiscovery = {}
local friendCache = {}

local function resolveMember(member)
    local ok, value = pcall(function() return member.Value end)
    if not ok then return nil end
    return typeof(value) == "Instance" and value.Name or tostring(value)
end

function PlayerDiscovery.getPackInfo(playerOrName, teamsFolder)
    local name = typeof(playerOrName) == "Instance" and playerOrName.Name or playerOrName
    teamsFolder = teamsFolder or workspace:FindFirstChild("Teams")
    if not name or not teamsFolder then return nil, nil end
    for _, pack in ipairs(teamsFolder:GetChildren()) do
        local leader, found
        for _, member in ipairs(pack:GetChildren()) do
            local memberName = resolveMember(member)
            if member.Name:lower() == "leader" then leader = memberName end
            if memberName == name then found = true end
        end
        if found then return leader, pack.Name end
    end
    return nil, nil
end

function PlayerDiscovery.samePack(first, second, teamsFolder)
    local firstLeader, firstPack = PlayerDiscovery.getPackInfo(first, teamsFolder)
    local secondLeader, secondPack = PlayerDiscovery.getPackInfo(second, teamsFolder)
    return (firstLeader and secondLeader and firstLeader == secondLeader)
        or (firstPack and secondPack and firstPack == secondPack) or false
end

function PlayerDiscovery.listPacks(teamsFolder)
    teamsFolder = teamsFolder or workspace:FindFirstChild("Teams")
    local result = { "None" }
    if teamsFolder then
        for _, pack in ipairs(teamsFolder:GetChildren()) do table.insert(result, pack.Name) end
        table.sort(result, function(a, b)
            if a == "None" then return true end
            if b == "None" then return false end
            return a:lower() < b:lower()
        end)
    end
    return result
end

function PlayerDiscovery.isFriend(localPlayer, otherPlayer)
    if not localPlayer or not otherPlayer then return false end
    local key = tostring(localPlayer.UserId) .. ":" .. tostring(otherPlayer.UserId)
    if friendCache[key] ~= nil then return friendCache[key] end
    local ok, result = pcall(function() return localPlayer:IsFriendsWith(otherPlayer.UserId) end)
    friendCache[key] = ok and result == true
    return friendCache[key]
end

function PlayerDiscovery.clearFriendCache()
    table.clear(friendCache)
end

function PlayerDiscovery.getRoot(player)
    local character = player and player.Character
    return character and (character:FindFirstChild("HumanoidRootPart") or character.PrimaryPart)
end

function PlayerDiscovery.isAlive(player)
    local humanoid = player and player.Character and player.Character:FindFirstChildOfClass("Humanoid")
    return humanoid ~= nil and humanoid.Health > 0 and PlayerDiscovery.getRoot(player) ~= nil
end

function PlayerDiscovery.isEligible(localPlayer, player, options)
    options = options or {}
    if not player or player == localPlayer or not player.Parent or not PlayerDiscovery.isAlive(player) then return false, "invalid" end
    if PlayerDiscovery.samePack(localPlayer, player, options.teamsFolder) then return false, "same-pack" end
    if not options.allowFriends and PlayerDiscovery.isFriend(localPlayer, player) then return false, "friend" end
    if options.pack and options.pack ~= "None" then
        local _, pack = PlayerDiscovery.getPackInfo(player, options.teamsFolder)
        if pack ~= options.pack then return false, "other-pack" end
