	["PredictiveAim"] = [[local PredictiveAim = {}

local function positiveIntercept(origin, target, velocity, speed)
	local offset = target - origin
	local a = velocity:Dot(velocity) - speed * speed
	local b = 2 * offset:Dot(velocity)
	local c = offset:Dot(offset)
	if math.abs(a) < 1e-6 then return b ~= 0 and math.max(0, -c / b) or 0 end
	local disc = b * b - 4 * a * c
	if disc < 0 then return offset.Magnitude / speed end
	local root = math.sqrt(disc)
	local t1, t2 = (-b - root) / (2 * a), (-b + root) / (2 * a)
	if t1 > 0 and t2 > 0 then return math.min(t1, t2) end
	return math.max(t1, t2, 0)
end

function PredictiveAim.point(origin, targetPart, projectileSpeed, releaseDelay, gravity)
	projectileSpeed = math.max(projectileSpeed or 150, 1)
	releaseDelay = math.max(releaseDelay or 0, 0)
	local velocity = targetPart.AssemblyLinearVelocity or Vector3.zero
	local travel = positiveIntercept(origin, targetPart.Position + velocity * releaseDelay, velocity, projectileSpeed)
	local point = targetPart.Position + velocity * (travel + releaseDelay)
	if gravity and gravity ~= 0 then point += Vector3.new(0, 0.5 * gravity * travel * travel, 0) end
	return point, travel
end

function PredictiveAim.smoothCamera(camera, point, alpha)
	if not (camera and point) then return false end
	local goal = CFrame.lookAt(camera.CFrame.Position, point)
	camera.CFrame = camera.CFrame:Lerp(goal, math.clamp(alpha or 0.18, 0, 1))
	return true
end

function PredictiveAim.aligned(camera, point, maxDegrees)
	local direction = point - camera.CFrame.Position
	if direction.Magnitude < 1e-4 then return true end
	local dot = math.clamp(camera.CFrame.LookVector:Dot(direction.Unit), -1, 1)
	return math.deg(math.acos(dot)) <= (maxDegrees or 2.5)
end

return PredictiveAim
