		gravity = options.gravity or 0, smoothing = options.smoothing or 0.18,
		alignment = options.alignmentDegrees or 2.5, fireInterval = options.fireInterval or 0.35,
		lastFire = 0,
	}, ProjectileController)
end

function ProjectileController:setTarget(part) self.targetPart = part end

function ProjectileController:start()
	if self.enabled then return end
	self.enabled = true
	self.connection = RunService.RenderStepped:Connect(function()
		local camera, target = workspace.CurrentCamera, self.targetPart
		if not (self.enabled and camera and target and target.Parent) then return end
		local point = PredictiveAim.point(camera.CFrame.Position, target, self.speed, self.delay, self.gravity)
		PredictiveAim.smoothCamera(camera, point, self.smoothing)
		if PredictiveAim.aligned(camera, point, self.alignment) and os.clock() - self.lastFire >= self.fireInterval then
			self.lastFire = os.clock()
			task.spawn(function() self.intent:click("left") end)
		end
	end)
end

function ProjectileController:stop()
	self.enabled = false
	if self.connection then self.connection:Disconnect(); self.connection = nil end
	self.targetPart = nil
end

function ProjectileController:destroy() self:stop() end

return ProjectileController
]],
	["runtime/lifecycle"] = [[local App = require("app")
local lifecycle = {}
local running
local environment = (getgenv and getgenv()) or _G

function lifecycle.start()
	if running then
		return false, "already running"
	end
	local previous = environment and environment.__ANIMAL_SIM_V2_APP
	if previous and type(previous.destroy) == "function" then
		pcall(function() previous:destroy() end)
	end
	running = App.new()
	if environment then environment.__ANIMAL_SIM_V2_APP = running end
	local ok, result = pcall(function() return running:start() end)
	if not ok then
		running:destroy()
		running = nil
		if environment then environment.__ANIMAL_SIM_V2_APP = nil end
		error(result, 0)
	end
	return result
end

function lifecycle.stop()
	if not running then
		return
	end
	running:destroy()
	running = nil
	if environment then environment.__ANIMAL_SIM_V2_APP = nil end
end

function lifecycle.isRunning()
	return running ~= nil
end

return lifecycle
]],
	["safe_zone"] = [[local SafeZone = {}

-- Current legacy geometry. Re-probe in the live game before promoting V2.
SafeZone.polygon = {
    Vector2.new(-47.553, 585.940),
    Vector2.new(-277.322, 672.467),
    Vector2.new(-344.602, 483.516),
    Vector2.new(-114.346, 401.818),
}

function SafeZone.contains(position)
    if typeof(position) ~= "Vector3" then
        return false
    end
    local point = Vector2.new(position.X, position.Z)
    local inside = false
    local previous = #SafeZone.polygon
    for index = 1, #SafeZone.polygon do
        local a, b = SafeZone.polygon[index], SafeZone.polygon[previous]
        local crosses = (a.Y > point.Y) ~= (b.Y > point.Y)
        if crosses then
            local x = (b.X - a.X) * (point.Y - a.Y) / (b.Y - a.Y) + a.X
            if point.X < x then
                inside = not inside
            end
        end
        previous = index
    end
    return inside
end

return SafeZone
]],
	["targeting"] = [[local CombatMath = require("combat_math")
local Discovery = require("player_discovery")

local Targeting = {}

local function distanceBetween(first, second)
    local a, b = Discovery.getRoot(first), Discovery.getRoot(second)
    return a and b and (a.Position - b.Position).Magnitude or math.huge
end

function Targeting.buildCandidates(localPlayer, players, options)
    options = options or {}
    local candidates = {}
    for _, player in ipairs(players) do
        local eligible, reason = Discovery.isEligible(localPlayer, player, options)
        if eligible then
            local matchup = CombatMath.getMatchup(localPlayer, player)
            if CombatMath.passesRatio(matchup, options.ratioThreshold) then
                table.insert(candidates, {
                    player = player,
                    matchup = matchup,
                    distance = distanceBetween(localPlayer, player),
                })
            elseif options.onRejected then
                local reason = CombatMath.passesTitleSafety(matchup) and "ratio" or "enemy-title"
                options.onRejected(player, reason, matchup)
            end
        elseif options.onRejected then
            options.onRejected(player, reason)
        end
    end
    return candidates
end

function Targeting.cluster(candidates, linkDistance)
    linkDistance = tonumber(linkDistance) or 10
    local clusters, visited = {}, {}
    for index = 1, #candidates do
        if not visited[index] then
            local cluster, queue = {}, { index }
            visited[index] = true
            local cursor = 1
            while cursor <= #queue do
                local currentIndex = queue[cursor]
                cursor = cursor + 1
                local current = candidates[currentIndex]
                table.insert(cluster, current)
                local currentRoot = Discovery.getRoot(current.player)
                if currentRoot then
                    for otherIndex = 1, #candidates do
                        if not visited[otherIndex] then
                            local otherRoot = Discovery.getRoot(candidates[otherIndex].player)
                            if otherRoot and (currentRoot.Position - otherRoot.Position).Magnitude <= linkDistance then
                                visited[otherIndex] = true
                                table.insert(queue, otherIndex)
                            end
                        end
                    end
                end
            end
            table.insert(clusters, cluster)
        end
    end
    return clusters
end

function Targeting.closestCluster(clusters)
    local selected, selectedDistance
    for _, cluster in ipairs(clusters) do
        local nearest = math.huge
        for _, candidate in ipairs(cluster) do nearest = math.min(nearest, candidate.distance) end
        if not selectedDistance or nearest < selectedDistance then
            selected, selectedDistance = cluster, nearest
        end
    end
    return selected, selectedDistance
end

function Targeting.chooseFromCluster(cluster, priority)
    priority = (priority or "Weakest"):lower()
    local chosen
    for _, candidate in ipairs(cluster or {}) do
        if not chosen then
            chosen = candidate
        elseif priority == "closest" and candidate.distance < chosen.distance then
            chosen = candidate
        elseif priority == "strongest" and candidate.matchup.ratio < chosen.matchup.ratio then
            chosen = candidate
        elseif priority == "weakest" and candidate.matchup.ratio > chosen.matchup.ratio then
            chosen = candidate
        end
    end
    return chosen
end

-- A pack selection intentionally overrides an individually selected player.
function Targeting.select(localPlayer, players, options)
    options = options or {}
    local selectedPack = options.selectedPack
    local selectedPlayer = options.selectedPlayer
    local hasPack = selectedPack and selectedPack ~= "None"
    local discoveryOptions = {
        teamsFolder = options.teamsFolder,
        allowFriends = options.allowFriends,
        isSafe = options.isSafe,
        pack = hasPack and selectedPack or nil,
        ratioThreshold = options.ratioThreshold,
        onRejected = options.onRejected,
    }
    local candidates = Targeting.buildCandidates(localPlayer, players, discoveryOptions)
    if not hasPack and selectedPlayer and selectedPlayer ~= "None" then
        for _, candidate in ipairs(candidates) do
            if candidate.player == selectedPlayer or candidate.player.Name == selectedPlayer then return candidate end
        end
        return nil
    end
    local clusters = Targeting.cluster(candidates, options.clusterDistance or 10)
    return Targeting.chooseFromCluster(Targeting.closestCluster(clusters), options.priority or "Weakest")
end

function Targeting.newLock(validator)
    local lock = { target = nil, reason = nil }
    function lock:get() return self.target end
    function lock:clear(reason) self.target, self.reason = nil, reason end
    function lock:set(player) self.target, self.reason = player, nil return player end
    function lock:resolve(candidate)
        if self.target then
            local valid, reason = validator(self.target)
            if valid then return self.target, true end
            self:clear(reason or "invalidated")
        end
        if candidate then return self:set(candidate.player or candidate), false end
        return nil, false
    end
    return lock
end

return Targeting
]],
	["ui_controller"] = [[local Players = game:GetService("Players")
local Venyx = require("vendor/venyx")
local Discovery = require("player_discovery")

local UIController = {}
UIController.__index = UIController

local function names()
	local result = {"None"}
	for _, player in ipairs(Players:GetPlayers()) do
		if player ~= Players.LocalPlayer then table.insert(result, player.Name) end
	end
	table.sort(result, function(a, b) if a == "None" then return true elseif b == "None" then return false end return a:lower() < b:lower() end)
	return result
end

local function toggle(section, title, default, setter)
	return section:addToggle({title = title, default = default, callback = setter})
end

function UIController.new(app, config)
	local self = setmetatable({app = app, config = config}, UIController)
	local ui = Venyx.new({title = "Animal Simulator V2 " .. config.version})
	self.ui = ui
	local combat = ui:addPage({title = "Combat"})
	local targeting = combat:addSection({title = "Targeting"})
	self.playerDropdown = targeting:addDropdown({
		title = "Target Player", source = names, signals = {Players.PlayerAdded, Players.PlayerRemoving},
		default = "None", refreshOptions = {fireCallback = true},
		callback = function(value) app:setOption("selectedPlayer", value or "None") end,
	})
	self.packDropdown = targeting:addDropdown({
		title = "Enemy Clan", source = Discovery.listPacks,
		signals = {workspace.DescendantAdded, workspace.DescendantRemoving},
		default = "None", refreshOptions = {fireCallback = true},
		callback = function(value) app:setOption("selectedPack", value or "None") end,
	})
	targeting:addDropdown({title = "Priority", list = {"Weakest", "Strongest", "Closest"}, default = "Weakest", callback = function(value) app:setOption("priority", value) end})
	targeting:addDropdown({title = "Minimum Hit Ratio", list = config.ratioOptions, default = tostring(config.defaultRatio), callback = function(value) app:setOption("ratio", tonumber(value) or config.defaultRatio) end})
	toggle(targeting, "Allow Friends", false, function(v) app:setOption("allowFriends", v) end)

	local modes = combat:addSection({title = "Engagement"})
	toggle(modes, "Legit Mode", true, function(v) app:setFeature("legit", v) end)
	toggle(modes, "Auto PVP", false, function(v) app:setFeature("autoPvp", v) end)
	toggle(modes, "Auto Zone", false, function(v) app:setFeature("autoZone", v) end)
	toggle(modes, "Auto Fire", false, function(v) app:setFeature("autoFire", v) end)
	toggle(modes, "Kill Aura (Remote)", false, function(v) app:setFeature("aura", v) end)
	toggle(modes, "Auto Zone Fakeouts", true, function(v) app:setFeature("fakeouts", v) end)

	local movement = ui:addPage({title = "Movement"})
	local moveModes = movement:addSection({title = "Controllers"})
	toggle(moveModes, "Follow Nearest Ally", false, function(v) app:setFeature("followAlly", v) end)
	toggle(moveModes, "Flight Chase", false, function(v) app:setFeature("flightChase", v) end)
	toggle(moveModes, "Mirror Target Jump", false, function(v) app:setFeature("autoJump", v) end)
	toggle(moveModes, "Remember WalkSpeed", false, function(v) app:setFeature("rememberWalkspeed", v) end)

	local utility = ui:addPage({title = "Utility"})
	local automation = utility:addSection({title = "Automation"})
	toggle(automation, "Auto Eat", false, function(v) app:setFeature("autoEat", v) end)
	toggle(automation, "Combat Overheads", false, function(v) app:setFeature("overheads", v) end)
	toggle(automation, "Movement Visuals", false, function(v) app:setFeature("visuals", v) end)
	automation:addButton({title = "Ghost Hit Target (Remote)", callback = function() app:ghostHit() end})
	automation:addButton({title = "Print All Teams", callback = function() app:printTeams() end})
	automation:addButton({title = "Force Join Selected Clan", callback = function() app:forceJoinPack() end})
	local scripts = utility:addSection({title = "Scripts"})
	scripts:addButton({title = "Load AW Script", callback = function() app:loadAw() end})

	return self
end

function UIController:refreshDynamicLists()
	self.playerDropdown:Update({list = names()})
	self.packDropdown:Update({list = Discovery.listPacks()})
end

function UIController:destroy()
	if self.ui then self.ui:Destroy() end
end

return UIController
]],
	["vendor/venyx"] = [[-- init
local player = game.Players.LocalPlayer
local mouse = player:GetMouse()

-- services
local input = game:GetService("UserInputService")
local run = game:GetService("RunService")
local tween = game:GetService("TweenService")
local tweeninfo = TweenInfo.new

-- additional
local utility = {}

-- themes
local objects = {}
local themes = {
	Background = Color3.fromRGB(24, 24, 24),
	Glow = Color3.fromRGB(0, 0, 0),
	Accent = Color3.fromRGB(10, 10, 10),
	LightContrast = Color3.fromRGB(20, 20, 20),
	DarkContrast = Color3.fromRGB(14, 14, 14),
	TextColor = Color3.fromRGB(255, 255, 255)
}

do
	function utility:Create(instance, properties, children)
		local object = Instance.new(instance)

		for i, v in pairs(properties or {}) do
			object[i] = v

			if typeof(v) == "Color3" then -- save for theme changer later
				local theme = utility:Find(themes, v)

				if theme then
					objects[theme] = objects[theme] or {}
					objects[theme][i] = objects[theme][i] or setmetatable({}, {_mode = "k"})

					objects[theme][i][#objects[theme][i] + 1] = object
				end
			end
		end

		for i, module in pairs(children or {}) do
			module.Parent = object
		end

		return object
	end

	function utility:Tween(instance, properties, duration, ...)
		tween:Create(instance, tweeninfo(duration, ...), properties):Play()
	end

	function utility:Wait()
		run.RenderStepped:Wait()
		return true
	end

	function utility:Find(table, value) -- table.find doesn't work for dictionaries
		for i, v in  pairs(table) do
			if v == value then
				return i
			end
		end
	end

	function utility:Sort(pattern, values)
		local new = {}
		pattern = pattern:lower()

		if pattern == "" then
			return values
		end

		for i, value in pairs(values) do
			if tostring(value):lower():find(pattern) then
				new[#new + 1] = value
			end
		end

		return new
	end

	function utility:Pop(object, shrink)
		local clone = object:Clone()

		clone.AnchorPoint = Vector2.new(0.5, 0.5)
		clone.Size = clone.Size - UDim2.new(0, shrink, 0, shrink)
		clone.Position = UDim2.new(0.5, 0, 0.5, 0)

		clone.Parent = object
		clone:ClearAllChildren()

		object.ImageTransparency = 1
		utility:Tween(clone, {Size = object.Size}, 0.2)

		coroutine.wrap(function()
			wait(0.2)

			object.ImageTransparency = 0
			clone:Destroy()
		end)()

		return clone
	end

	function utility:InitializeKeybind()
		if self._keybindInitialized then
			return
		end
		self._keybindInitialized = true
		self.keybinds = {}
		self.ended = {}

		input.InputBegan:Connect(function(key, gameProcessedEvent)
			if self.keybinds[key.KeyCode] then
				for i, bind in pairs(self.keybinds[key.KeyCode]) do
					if (bind.gameProcessedEvent == gameProcessedEvent) then
						bind.callback()
					end
				end
			end
		end)

		input.InputEnded:Connect(function(key)
			if key.UserInputType == Enum.UserInputType.MouseButton1 then
				for i, callback in pairs(self.ended) do
					callback()
				end
			end
		end)
	end

	function utility:BindToKey(key, callback, gameProcessedEvent)

		self.keybinds[key] = self.keybinds[key] or {}

		table.insert(self.keybinds[key], {callback = callback, gameProcessedEvent = gameProcessedEvent or false})

		return {
			UnBind = function()
				for i, keybindData in pairs(self.keybinds[key]) do
					if keybindData.callback == callback then
						table.remove(self.keybinds[key], i)
					end
				end
			end
		}
	end

	function utility:KeyPressed() -- yield until next key is pressed
		local key = input.InputBegan:Wait()

		while key.UserInputType ~= Enum.UserInputType.Keyboard	 do
			key = input.InputBegan:Wait()
		end

		wait() -- overlapping connection

		return key
	end

	function utility:DraggingEnabled(frame, parent)

		parent = parent or frame

		-- stolen from wally or kiriot, kek
		local dragging = false
		local dragInput, mousePos, framePos

		frame.InputBegan:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1 then
				dragging = true
				mousePos = input.Position
				framePos = parent.Position

				input.Changed:Connect(function()
					if input.UserInputState == Enum.UserInputState.End then
						dragging = false
					end
				end)
			end
		end)

		frame.InputChanged:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseMovement then
				dragInput = input
			end
		end)

		input.InputChanged:Connect(function(input)
			if input == dragInput and dragging then
				local delta = input.Position - mousePos
				parent.Position  = UDim2.new(framePos.X.Scale, framePos.X.Offset + delta.X, framePos.Y.Scale, framePos.Y.Offset + delta.Y)
			end
		end)

	end

	function utility:DraggingEnded(callback)
		self.ended[#self.ended + 1] = callback
	end

end

-- classes

local library = {} -- main
local page = {}
local section = {}

do
	library.__index = library
	page.__index = page
	section.__index = section

	-- new classes

	function library.new(data)
		data = data or {}
