				BackgroundTransparency = 1,
				Position = UDim2.new(0, 10, 0.5, 1),
				Size = UDim2.new(0.5, 0, 1, 0),
				ZIndex = 3,
				Font = Enum.Font.Gotham,
				Text = this.title,
				TextColor3 = themes.TextColor,
				TextSize = 12,
				TextTransparency = 0.10000000149012,
				TextXAlignment = Enum.TextXAlignment.Left
			}),
			utility:Create("ImageLabel", {
				Name = "Button",
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				Position = UDim2.new(1, -50, 0.5, -8),
				Size = UDim2.new(0, 40, 0, 16),
				ZIndex = 2,
				Image = "rbxassetid://5028857472",
				ImageColor3 = themes.LightContrast,
				ScaleType = Enum.ScaleType.Slice,
				SliceCenter = Rect.new(2, 2, 298, 298)
			}, {
				utility:Create("ImageLabel", {
					Name = "Frame",
					BackgroundTransparency = 1,
					Position = UDim2.new(0, 2, 0.5, -6),
					Size = UDim2.new(1, -22, 1, -4),
					ZIndex = 2,
					Image = "rbxassetid://5028857472",
					ImageColor3 = themes.TextColor,
					ScaleType = Enum.ScaleType.Slice,
					SliceCenter = Rect.new(2, 2, 298, 298)
				})
			})
		})
		local module = {Instance = toggle, Options = this}
		self.modules[#self.modules + 1] = module
		--self:Resize()

		self:updateToggle(module)

		function this:Update(dataOptions)
			-- // Overwriting settings
            for i,v in pairs(dataOptions) do
				if (module.Options[i] ~= nil and i ~= "Update") then
					module.Options[i] = v
				end
			end

			return section:updateToggle(module)
		end

		function module:Update(dataOptions)
			return this:Update(dataOptions)
		end

		function module:GetValue()
			return this.toggled
		end

		function module:SetValue(value, fireCallback)
			local nextValue = value == true
			local changed = this.toggled ~= nextValue
			this.toggled = nextValue
			ownerSection:updateToggle(module)
			if changed and fireCallback then
				this.callback(nextValue)
			end
			return nextValue
		end

		module.Get = module.GetValue
		module.Set = module.SetValue

		function module:Destroy()
			module.Instance:Destroy()
		end

		toggle.MouseButton1Click:Connect(function()
			this.toggled = not this.toggled
			self:updateToggle(module)

			this.callback(this.toggled)
		end)

		return module
	end

