		self:updateSlider(module)

		utility:DraggingEnded(function()
			dragging = false
		end)

		slider.MouseButton1Down:Connect(function()
			dragging = true

			while dragging do
				utility:Tween(circle, {ImageTransparency = 0}, 0.1)

				this.value = nil
				this.value = self:updateSlider(module)
				this.callback(this.value)

				utility:Wait()
