            for i,v in pairs(dataOptions) do
                if (module.Options[i] and i ~= "Update") then
                    module.Options[i] = tostring(v)
                end
			end

			return section:updateSlider(module)
		end

		return module
	end

	function section:addDropdown(data)
		local ownerSection = self
		local function normalizeList(values)
			local normalized = {}
			for _, value in ipairs(values or {}) do
				normalized[#normalized + 1] = tostring(value)
			end
			return normalized
		end

		local this = {}
		this.source = data.source or (type(data.list) == "function" and data.list or nil)
		local initialList = data.list
		if this.source then
			local ok, result = pcall(this.source)
			if ok then
				initialList = result
			else
				warn("[Venyx] Initial dropdown source failed: " .. tostring(result))
				initialList = {}
			end
		end
		this.list = normalizeList(initialList)
		this.backuplist = normalizeList(this.list)
		this.title = data.title or "nil title"
		this.placeholder = this.title
