					Active = true,
					BackgroundTransparency = 1,
					BorderSizePixel = 0,
					Position = UDim2.new(0, 4, 0, 4),
					Size = UDim2.new(1, -8, 1, -8),
					CanvasPosition = Vector2.new(0, 28),
					CanvasSize = UDim2.new(0, 0, 0, 120),
					ZIndex = 2,
					ScrollBarThickness = 3,
					ScrollBarImageColor3 = themes.DarkContrast
				}, {
					utility:Create("UIListLayout", {
						SortOrder = Enum.SortOrder.LayoutOrder,
						Padding = UDim.new(0, 4)
					})
				})
			})
		})

		local module = {Instance = dropdown, Options = this}
		self.modules[#self.modules + 1] = module
		--self:Resize()

		local search = dropdown.Search
		local focused

		search.Button.MouseButton1Click:Connect(function()
			if search.Button.Rotation == 0 then
				this.title = nil
				self:updateDropdown(module)
			else
				this.title = nil
				self:updateDropdown(module, {update = {}})
			end
		end)

		search.TextBox.Focused:Connect(function()
			if search.Button.Rotation == 0 then
				this.title = nil
				self:updateDropdown(module, {update = {}})
			end

			focused = true
		end)

		search.TextBox.FocusLost:Connect(function()
			focused = false
		end)

		search.TextBox:GetPropertyChangedSignal("Text"):Connect(function()
			if focused then
				local list = utility:Sort(search.TextBox.Text, this.list)

				this.title = nil
				self:updateDropdown(module, {update = list})
			end
		end)

		dropdown:GetPropertyChangedSignal("Size"):Connect(function()
			self:Resize()
		end)

		function this:Update(dataOptions)
			if dataOptions.list ~= nil then
				return module:SetList(dataOptions.list, dataOptions)
			end
			for key, value in pairs(dataOptions) do
				if key ~= "Update" and module.Options[key] ~= nil then
					module.Options[key] = value
				end
			end
			return section:updateDropdown(module, {noOpen = true})
		end

		function module:Update(dataOptions)
			return this:Update(dataOptions)
		end

		function module:GetValue()
			return this.value
		end

		function module:SetValue(value, fireCallback)
			value = value ~= nil and tostring(value) or nil
			local changed = this.value ~= value
			this.value = value
			this.title = value or this.placeholder
			section:updateDropdown(module, {noOpen = true})
			if changed and fireCallback then
				this.callback(value)
			end
			return value
		end

		function module:SetList(values, options)
			options = options or {}
			local nextList = normalizeList(values)
			local previous = this.value
			local same = #nextList == #this.list
			if same then
				for index, value in ipairs(nextList) do
					if this.list[index] ~= value then same = false break end
				end
			end
			local previousIsValid = previous ~= nil and table.find(nextList, previous) ~= nil
			if same and this._listInitialized and options.preserve ~= false
				and (previousIsValid or (#nextList == 0 and previous == nil)) then
				return previous
			end
			this.list = nextList
			this.backuplist = normalizeList(nextList)
			local keep = options.preserve ~= false and previous and table.find(nextList, previous) ~= nil
			local fallback = options.fallback
			if fallback == nil then fallback = this.default end
			if fallback ~= nil then fallback = tostring(fallback) end
			if not keep and (not fallback or not table.find(nextList, fallback)) then
				fallback = nextList[1]
			end
			this.value = keep and previous or fallback
			this.title = this.value or this.placeholder
			this._listInitialized = true
			section:updateDropdown(module, {noOpen = true})
			if previous ~= this.value and options.fireCallback then
				this.callback(this.value)
			end
			return this.value
		end

		module.SetItems = module.SetList
		module.Get = module.GetValue
		module.Set = module.SetValue

		function module:Refresh(options)
			if type(this.source) ~= "function" then
				return this.value
			end
			local ok, values = pcall(this.source)
			if not ok then
				warn("[Venyx] Dropdown source failed: " .. tostring(values))
				return this.value
			end
			return module:SetList(values, options)
		end

		function module:BindList(signals, source)
			module:UnbindList()
			if source then this.source = source end
			module._listConnections = {}
			for _, signal in ipairs(signals or {}) do
				local connection = ownerSection.page.library:Connect(signal, function()
					task.defer(function()
						if module.Instance and module.Instance.Parent then
							module:Refresh(this.refreshOptions)
						end
					end)
				end)
				module._listConnections[#module._listConnections + 1] = connection
			end
			return module:Refresh(this.refreshOptions)
		end

		function module:UnbindList()
			for _, connection in ipairs(module._listConnections or {}) do
				pcall(function() connection:Disconnect() end)
			end
			module._listConnections = {}
		end

		function module:Destroy()
			module:UnbindList()
			module.Instance:Destroy()
		end

		module:SetList(this.list, {fallback = this.default})
		if data.signals then
			module:BindList(data.signals)
		end

		return module
	end

	-- class functions

	function library:SelectPage(data)
		local selectedPage
		local toggle
		if type(data) == "number" then
			selectedPage = self.pages[data]
			toggle = true
		elseif type(data) == "table" and data.button and data.sections then
			selectedPage = data
			toggle = true
		else
			selectedPage = data and data.page
			toggle = data and data.toggle
		end
		if not selectedPage then
			return false
		end

		if toggle and self.focusedPage == page then -- already selected
			return
		end

		local button = selectedPage.button

		if toggle then
			-- page button
			button.Title.TextTransparency = 0
			button.Title.Font = Enum.Font.GothamSemibold

			if button:FindFirstChild("Icon") then
				button.Icon.ImageTransparency = 0
			end

			-- update selected page
			local focusedPage = self.focusedPage
			self.focusedPage = selectedPage

			if focusedPage then
				self:SelectPage({
					page = focusedPage
				})
			end

			-- sections
			local existingSections = focusedPage and #focusedPage.sections or 0
			local sectionsRequired = #selectedPage.sections - existingSections

			selectedPage:Resize()

			for i = 1, #selectedPage.sections do
				local pageSection = selectedPage.sections[i]
				pageSection.container.Parent.ImageTransparency = 0
			end
			if sectionsRequired < 0 then -- "hides" some sections
				for i = existingSections, #selectedPage.sections + 1, -1 do
					local pageSection = focusedPage.sections[i].container.Parent

					utility:Tween(pageSection, {ImageTransparency = 1}, 0.1)
				end
			end

			wait(0.1)
			selectedPage.container.Visible = true

			if focusedPage then
				focusedPage.container.Visible = false
			end

			if sectionsRequired > 0 then -- "creates" more section
				for i = existingSections + 1, #selectedPage.sections do
					local pageSection = selectedPage.sections[i].container.Parent

					pageSection.ImageTransparency = 1
					utility:Tween(pageSection, {ImageTransparency = 0}, 0.05)
				end
			end

			wait(0.05)

			for i = 1, #selectedPage.sections do
				local pageSection = selectedPage.sections[i]
				utility:Tween(pageSection.container.Title, {TextTransparency = 0}, 0.1)
				pageSection:Resize(true)

				wait(0.05)
			end

			wait(0.05)
			selectedPage:Resize(true)
		else
			-- page button
			button.Title.Font = Enum.Font.Gotham
			button.Title.TextTransparency = 0.65

			if button:FindFirstChild("Icon") then
				button.Icon.ImageTransparency = 0.65
			end

			-- sections
			for i = 1, #selectedPage.sections do
				local pageSection = selectedPage.sections[i]
				utility:Tween(pageSection.container.Parent, {Size = UDim2.new(1, -10, 0, 28)}, 0.1)
				utility:Tween(pageSection.container.Title, {TextTransparency = 1}, 0.1)
			end

			wait(0.1)

			selectedPage.lastPosition = selectedPage.container.CanvasPosition.Y
			selectedPage:Resize()
		end
	end

	function page:Resize(scroll)
		local padding = 10
		local size = 0

		for i = 1, #self.sections do
			local pageSection = self.sections[i]
			size = size + pageSection.container.Parent.AbsoluteSize.Y + padding
		end

		self.container.CanvasSize = UDim2.new(0, 0, 0, size)
		self.container.ScrollBarImageTransparency = size > self.container.AbsoluteSize.Y

		if scroll then
			utility:Tween(self.container, {CanvasPosition = Vector2.new(0, self.lastPosition or 0)}, 0.2)
		end
	end

	function section:Resize(smooth)

		if self.page.library.focusedPage ~= self.page then
			return
		end

		local padding = 4
		local size = (4 * padding) + self.container.Title.AbsoluteSize.Y -- offset

		for i, module in pairs(self.modules) do
			size = size + module.Instance.AbsoluteSize.Y + padding
		end

		if smooth then
			utility:Tween(self.container.Parent, {Size = UDim2.new(1, -10, 0, size)}, 0.05)
		else
			self.container.Parent.Size = UDim2.new(1, -10, 0, size)
			self.page:Resize()
		end
	end

	function section:getModule(info)
		for i = 1, #self.modules do
			local module = self.modules[i]
			local object = module.Instance

			if (((object:FindFirstChild("Title") or object:FindFirstChild("TextBox", true)).Text == info) or object == info) then
				return module
			end
		end

		error("No module found under "..tostring(info.Instance))
	end

	-- updates

	function section:updateButton(module)
		module.Instance.Title.Text = module.Options.title
	end

	function section:updateToggle(module)
		local toggle = module.Instance
		local options = module.Options

		local position = {
			In = UDim2.new(0, 2, 0.5, -6),
			Out = UDim2.new(0, 20, 0.5, -6)
		}

		local frame = toggle.Button.Frame
		local selectedPosition = options.toggled and "Out" or "In"

		toggle.Title.Text = module.Options.title

		utility:Tween(frame, {
			Size = UDim2.new(1, -22, 1, -9),
			Position = position[selectedPosition] + UDim2.new(0, 0, 0, 2.5)
		}, 0.2)

		wait(0.1)
		utility:Tween(frame, {
			Size = UDim2.new(1, -22, 1, -4),
			Position = position[selectedPosition]
		}, 0.1)
	end

	function section:updateTextbox(module)
		module.Instance.Title.Text = module.Options.title
		module.Instance.Button.Textbox.Text = module.Options.default
	end

	function section:updateKeybind(module)
		local keybind = module.Instance
		local options = module.Options

		if (typeof(options.key) == "Instance" and options.key:IsA("InputObject")) then
			options.key = options.key.KeyCode
		end

		local text = keybind.Button.Text
		local bind = self.binds[keybind]

		keybind.Title.Text = module.Options.title

		if bind.connection then
			bind.connection = bind.connection:UnBind()
		end

		if options.key ~= Enum.KeyCode.Unknown then
			self.binds[keybind].connection = utility:BindToKey(options.key, bind.callback, options.gameProcessedEvent)
			text.Text = input:GetStringForKeyCode(options.key)
		else
			text.Text = "Unknown"
		end
	end

	function section:updateColorPicker(module)
		local colorpicker = module.Instance
		local options = module.Options

		local picker = self.colorpickers[colorpicker]
		local tab = picker.tab

		colorpicker.Title.Text = options.title
		tab.Title.Text = options.title

		local color3
		local hue, sat, brightness

		if (typeof(options.default) == "table") then
			hue, sat, brightness = unpack(options.default)
			color3 = Color3.fromHSV(hue, sat, brightness)
		else
			color3 = options.default
			hue, sat, brightness = Color3.toHSV(color3)
		end

		utility:Tween(colorpicker.Button, {ImageColor3 = color3}, 0.5)
		utility:Tween(tab.Container.Color.Select, {Position = UDim2.new(hue, 0, 0, 0)}, 0.1)

		utility:Tween(tab.Container.Canvas, {ImageColor3 = Color3.fromHSV(hue, 1, 1)}, 0.5)
		utility:Tween(tab.Container.Canvas.Cursor, {Position = UDim2.new(sat, 0, 1 - brightness)}, 0.5)

		for i, container in pairs(tab.Container.Inputs:GetChildren()) do
			if container:IsA("ImageLabel") then
				local value = math.clamp(color3[container.Name], 0, 1) * 255

				container.Textbox.Text = math.floor(value)
				--callback(container.Name:lower(), value)
			end
		end
	end

	function section:updateSlider(module)
		local slider = module.Instance
		local options = module.Options

		slider.Title.Text = options.title

		local bar = slider.Slider.Bar
		local percent = (mouse.X - bar.AbsolutePosition.X) / bar.AbsoluteSize.X

		if options.value then
			percent = (options.value - options.min) / (options.max - options.min)
		end

		local function round(what, precision)
			if (precision == 0) then
				return math.floor(what)
			elseif (precision == -1) then
				return what
			else
				return math.floor(what * math.pow(10, precision) + 0.5) / math.pow(10, precision)
			end
		end

		percent = math.clamp(percent, 0, 1)
		options.value = options.value or round(options.min + (options.max - options.min) * percent, options.precision)

		slider.TextBox.Text = options.value
		utility:Tween(bar.Fill, {Size = UDim2.new(percent, 0, 1, 0)}, 0.1)

		if options.value ~= options.lvalue and slider.ImageTransparency == 0 then
			utility:Pop(slider, 10)
		end

		return options.value
	end

	function section:updateDropdown(module, aOptions)
		local dropdown = module.Instance
		local options = module.Options
		aOptions = aOptions or {}

		-- Backward compatibility for older scripts that called
		-- section:updateDropdown(control, replacementOptions) directly.
		if aOptions.list ~= nil then
			local replacement = {}
			for _, value in ipairs(aOptions.list or {}) do
				replacement[#replacement + 1] = tostring(value)
			end
			options.list = replacement
			options.backuplist = table.clone(replacement)
			if aOptions.callback ~= nil then options.callback = aOptions.callback end
			if aOptions.default ~= nil then options.default = tostring(aOptions.default) end
			if aOptions.title ~= nil then options.placeholder = tostring(aOptions.title) end
			local selected = options.default
			if selected and not table.find(replacement, selected) then selected = replacement[1] end
			options.value = selected
			options.title = selected or options.placeholder
			aOptions = {noOpen = true}
		end

		if (options.title) then
			dropdown.Search.TextBox.Text = options.title
		end

		local entries = 0

		utility:Pop(dropdown.Search, 10)

		for i, button in pairs(dropdown.List.Frame:GetChildren()) do
			if button:IsA("ImageButton") then
				button:Destroy()
			end
		end

		local list = aOptions.update or options.list

		for i, value in ipairs(list) do
			local button = utility:Create("ImageButton", {
				Parent = dropdown.List.Frame,
				BackgroundTransparency = 1,
				BorderSizePixel = 0,
				Size = UDim2.new(1, 0, 0, 30),
				ZIndex = 2,
				Image = "rbxassetid://5028857472",
				ImageColor3 = themes.DarkContrast,
				ScaleType = Enum.ScaleType.Slice,
				SliceCenter = Rect.new(2, 2, 298, 298)
			}, {
				utility:Create("TextLabel", {
					BackgroundTransparency = 1,
					Position = UDim2.new(0, 10, 0, 0),
					Size = UDim2.new(1, -10, 1, 0),
					ZIndex = 3,
					Font = Enum.Font.Gotham,
					Text = value,
					TextColor3 = themes.TextColor,
					TextSize = 12,
					TextXAlignment = "Left",
					TextTransparency = 0.10000000149012
				})
			})

			button.MouseButton1Click:Connect(function()
				options.value = value
				options.title = value
				options.callback(value)
				self:updateDropdown(module, {update = value and {} or false})
			end)

			entries = entries + 1
		end

		local frame = dropdown.List.Frame

		if (not aOptions.noOpen) then
			utility:Tween(dropdown, {Size = UDim2.new(1, 0, 0, (entries == 0 and 30) or math.clamp(entries, 0, 3) * 34 + 38)}, 0.3)
			utility:Tween(dropdown.Search.Button, {Rotation = not aOptions.update and 180 or 0}, 0.3)
		end

		if entries > 3 then

			for i, button in pairs(dropdown.List.Frame:GetChildren()) do
				if button:IsA("ImageButton") then
					button.Size = UDim2.new(1, -6, 0, 30)
				end
			end

			frame.CanvasSize = UDim2.new(0, 0, 0, (entries * 34) - 4)
			frame.ScrollBarImageTransparency = 0
		else
			frame.CanvasSize = UDim2.new(0, 0, 0, 0)
			frame.ScrollBarImageTransparency = 1
		end
	end
end

--getgenv().Venyx = library
return library
]],
}

local moduleCache = {}
local loading = {}

local function requireModule(id)
	if type(id) ~= "string" then
		error("Animal Sim V2 modules must be required by string id", 2)
	end
	if moduleCache[id] ~= nil then
		return moduleCache[id]
	end
	if loading[id] then
		error(("Circular Animal Sim V2 module dependency: %s"):format(id), 2)
	end
	local source = MODULE_SOURCES[id]
	if source == nil then
		error(("Unknown Animal Sim V2 module: %s"):format(id), 2)
	end
	loading[id] = true
	local compiled, compileError = loadstring("return function(require)\n" .. source .. "\nend", "@animal-sim-v2/" .. id .. ".lua")
	if not compiled then
		loading[id] = nil
		error(("Failed to compile module %s: %s"):format(id, tostring(compileError)), 2)
	end
	local loader = compiled()
	local ok, result = pcall(loader, requireModule)
	loading[id] = nil
	if not ok then
		error(("Failed to load module %s: %s"):format(id, tostring(result)), 2)
	end
	if result == nil then result = true end
	moduleCache[id] = result
	return result
end

return requireModule("entry")
